// Accept { docId | docUrl, slug }.
const body = $input.first().json.body || $input.first().json;
let docId = (body.docId || '').trim();
const url = (body.docUrl || '').trim();
if (!docId && url) {
  const m = url.match(/\/d\/([a-zA-Z0-9_-]+)/);
  if (m) docId = m[1];
}
if (!docId) throw new Error('Provide docId or docUrl');
const slug = (body.slug || '').trim();
if (!slug || !/^[a-z0-9-]+$/.test(slug)) {
  throw new Error('Provide a valid slug (lowercase letters, numbers, hyphens)');
}
return [{ json: { docId, slug, filename: slug + '.json' } }];

// Parse the exported HTML into a blog JSON payload.
//
// Expected Google Doc structure:
//   <Article Title>            (Heading 1, or first non-empty line)
//   META: <SEO meta description>
//   CATEGORY: <category>       (optional)
//   IMAGE: <hero image URL>    (optional)
//   READTIME: 7 min read       (optional)
//   --- CONTENT ---
//   <article body>
//   --- FAQS ---
//   Q: question one?
//   A: answer one.
//
const input = $input.first().json;
let html = typeof input === 'string' ? input : (input.data || input.body || '');
if (!html) throw new Error('No HTML returned from Drive export');

html = html.replace(/<style[\s\S]*?<\/style>/gi, '');
const bodyMatch = html.match(/<body[^>]*>([\s\S]*?)<\/body>/i);
if (bodyMatch) html = bodyMatch[1];

const stripTags = (s) => (s || '')
  .replace(/<[^>]+>/g, '')
  .replace(/&nbsp;/g, ' ').replace(/&amp;/g, '&')
  .replace(/&lt;/g, '<').replace(/&gt;/g, '>')
  .replace(/&quot;/g, '"').replace(/&#39;/g, "'")
  .trim();
const text = stripTags(html);

let title = '';
const h1 = html.match(/<h1[^>]*>([\s\S]*?)<\/h1>/i);
if (h1) {
  title = stripTags(h1[1]);
} else {
  title = (text.split('\n').map(s => s.trim()).find(Boolean)) || '';
}

const takeLine = (re) => {
  const m = text.match(re);
  return m ? m[1].trim() : '';
};
const metaDescription = takeLine(/META:\s*([^\n]+)/i);
const category = takeLine(/CATEGORY:\s*([^\n]+)/i) || 'General';
const image = takeLine(/IMAGE:\s*([^\n]+)/i);
const readTime = takeLine(/READTIME:\s*([^\n]+)/i) || '5 min read';

const contentSplit = html.split(/---\s*CONTENT\s*---/i);
let rest = contentSplit[1] || html;
const faqSplit = rest.split(/---\s*FAQS\s*---/i);
let contentHtml = (faqSplit[0] || '').trim();
const faqBlock = (faqSplit[1] || '').trim();

contentHtml = contentHtml.replace(/<p[^>]*>\s*(META|CATEGORY|IMAGE|READTIME):[^<]*<\/p>/gi, '');
contentHtml = contentHtml.replace(/\sclass="[^"]*"/g, '');
contentHtml = contentHtml.replace(/<span[^>]*>/g, '').replace(/<\/span>/g, '');

const faqText = stripTags(faqBlock);
const faqs = [];
const lines = faqText.split(/\n+/).map(l => l.trim()).filter(Boolean);
let currentQ = null;
for (const line of lines) {
  if (/^Q[:.]/i.test(line)) {
    currentQ = line.replace(/^Q[:.]\s*/i, '').trim();
  } else if (/^A[:.]/i.test(line) && currentQ) {
    faqs.push({ q: currentQ, a: line.replace(/^A[:.]\s*/i, '').trim() });
    currentQ = null;
  } else if (faqs.length && !/^Q[:.]/i.test(line)) {
    faqs[faqs.length - 1].a += ' ' + line;
  }
}

const slug = $('Parse input').first().json.slug;
const payload = {
  title,
  metaTitle: title,
  metaDescription,
  subtitle: metaDescription,
  category,
  date: new Date().toLocaleDateString('en-US', { month: 'long', year: 'numeric' }),
  readTime,
  image,
  content: contentHtml,
  faqs
};

return [{ json: { slug, payload, jsonText: JSON.stringify(payload, null, 2) } }];

// Build a Drive multipart/related upload body so a single HTTP POST creates the file.
const slug = $json.slug;
const filename = $('Parse input').first().json.filename;
const jsonText = $json.jsonText;
const metadata = {
  name: filename,
  mimeType: 'application/json',
  parents: ['13CFbBbe4SesEhAXF7xCSy1wq6VMRB0Y9']
};
const boundary = 'pblb-' + Date.now() + '-' + Math.random().toString(36).slice(2);
const body = [
  '--' + boundary,
  'Content-Type: application/json; charset=UTF-8',
  '',
  JSON.stringify(metadata),
  '--' + boundary,
  'Content-Type: application/json',
  '',
  jsonText,
  '--' + boundary + '--',
  ''
].join('\r\n');
return [{ json: { slug, filename, contentType: 'multipart/related; boundary=' + boundary, body } }];
